        {type:"intro",title:"More...than: comparatives with plus",desc:"To say something is MORE than something else, French uses plus + adjective + que. This is the most common comparative structure.",goals:["Form comparatives with plus...que","Use adjective agreement in comparatives","Compare people and things"]},
        {type:"tip",title:"Comparative formation",text:"plus + ADJECTIVE + que = more...than\n\nParis est plus grand que Lyon.\n(Paris is bigger than Lyon.)\n\nElle est plus intelligente que lui.\n(She is smarter than him.)\n\nThe adjective still agrees with the subject!\nMasculine: plus grand que\nFeminine: plus grande que\nPlural: plus grands/grandes que"},
        {type:"teach",trg:"plus grand que",src:"bigger/taller than",pos:"adj",gender:null,phonetic:"plew GRAHN kuh",note:"Plus + adjective + que = more...than.\nGrand agrees with the subject (Paris = masc.).\nQue = than.",example:"A: Paris ou Lyon, quelle ville est plus grande?\nB: Paris est plus grand que Lyon.\nA: Beaucoup plus grand!",exampleSrc:"A: Paris or Lyon, which city is bigger?\nB: Paris is bigger than Lyon.\nA: Much bigger!",funFact:"Bigger than. Comparative of superiority. Plus + adj + que."},
        {type:"teach",trg:"moins cher que",src:"cheaper than / less expensive than",pos:"adj",gender:null,phonetic:"mwan SHAIR kuh",note:"Moins + adjective + que = less...than.\nMoins = less (opposite of plus).\nCher = expensive.",example:"A: Le bus ou le taxi?\nB: Le bus est moins cher que le taxi.\nA: Mais le taxi est plus rapide!",exampleSrc:"A: The bus or the taxi?\nB: The bus is cheaper than the taxi.\nA: But the taxi is faster!",funFact:"Cheaper than. Comparative of inferiority. Moins + adj + que."},
        {type:"teach",trg:"aussi rapide que",src:"as fast as",pos:"adj",gender:null,phonetic:"oh-SEE rah-PEED kuh",note:"Aussi + adjective + que = as...as.\nAussi = equally / as.\nUsed for equal comparisons.",example:"A: Le TGV est rapide!\nB: Oui, il est presque aussi rapide que l'avion.\nA: C'est impressionnant.",exampleSrc:"A: The TGV is fast!\nB: Yes, it's almost as fast as the plane.\nA: That's impressive.",funFact:"As fast as. Equality comparative. Aussi + adj + que."},
        {type:"mc",q:"'Marie est ___ grande ___ Pierre.' (taller than)",opts:["plus / que","moins / que","aussi / que","plus / de"],ans:"plus / que",hint:"More + adjective + than = which structure?"},
        {type:"fb",opts:["plus","moins","aussi","très"],hint:"French is harder than English. More + adjective + que.",s:"Le français est {1} difficile que l'anglais. (more)",a:"plus"},
        {type:"mc",q:"In 'Elle est plus intelligente que lui', why -e on intelligente?",opts:["Because of plus","Because elle is feminine","Because of que","Random"],ans:"Because elle is feminine",hint:"The adjective agrees with the subject, not with what's compared."},
        {type:"fb",opts:["moins","plus","aussi","très"],hint:"This film is less interesting. Less + adjective + que.",s:"Ce film est {1} intéressant que l'autre. (less)",a:"moins"},
        {type:"match",pairs:[{trg:"plus...que",src:"more...than"},{trg:"moins...que",src:"less...than"},{trg:"aussi...que",src:"as...as"},{trg:"que",src:"than / as"}]},
        {type:"mc",q:"'Mon frère est plus ___ que moi.' Choose the correctly agreed form of the adjective (older).",opts:["Âgés","Âgée","Âgé","Âgées"],ans:"Âgé",hint:"The noun it modifies is masculine singular. Match the adjective ending."},
        {type:"drag_fill",hint:"My sister is as athletic as me. Equal comparison.",s:"Ma soeur est {1} sportive {2} moi. (as...as)",blanks:{"1":"aussi","2":"que"},pool:["aussi","plus","que","de"]},
        {type:"mc",q:"Negative comparison: 'Il n'est pas aussi grand que toi' means:",opts:["He's taller than you","He's the shortest","He's the tallest","He's not as tall as you"],ans:"He's not as tall as you",hint:"Not + as...as = negative equality comparison."},
        {type:"drag_fill",hint:"Apples are cheaper than strawberries. Less expensive.",s:"Les pommes sont {1} chères {2} les fraises. (less...than)",blanks:{"1":"moins","2":"que"},pool:["moins","plus","que","de"]},
        {type:"match",pairs:[{trg:"plus grand que",src:"bigger than"},{trg:"moins cher que",src:"cheaper than"},{trg:"aussi rapide que",src:"as fast as"},{trg:"pas aussi bon que",src:"not as good as"}]},
        {type:"mc",q:"To emphasize: 'beaucoup plus grand' means:",opts:["Much bigger","A little bigger","Not bigger","The biggest"],ans:"Much bigger",hint:"Beaucoup reinforces the comparison = … more."},
        {type:"drag_fill",hint:"This city is much ___ beautiful. Beaucoup reinforces the comparison.",s:"Cette ville est beaucoup {1} belle {2} la mienne. (more...than)",blanks:{"1":"plus","2":"que"},pool:["plus","moins","que","de"]},
        {type:"mc",q:"Which modifiers work with comparatives?",opts:["Only beaucoup","Beaucoup, un peu, bien","Only très","No modifiers allowed"],ans:"Beaucoup, un peu, bien",hint:"Much more, a little more, way more = all valid."}
